# Determine type for each span by checking preceding context 100 chars before
def classify_span(start):
    context_start = max(0, start - 100)
    context = text[context_start:start]
    if 'قال النبي' in context or 'قال النبي صلى الله عليه وسلم' in context or 'الأحاديث' in context:
        return 'Hadeeth'
    else:
        # Check for "قال الله" or "سورة"
        if 'قال الله' in context:
            return 'Aya'
        else:
            # use line detection
            prev_line = text.rfind('\n', 0, start)
            line = text[prev_line+1:start]
            if 'النبي' in line:
                return 'Hadeeth'
            return 'Aya'

for s in spans:
    s['type'] = classify_span(s['start'])
spans

# Build the JSON object per schema with all invalid entries and computed spans
citations = []
for s in spans:
    entry = {
        "span_start": s['start'],
        "span_end": s['end'],
        "span_text": s['text'],
        "citation_type": "Aya" if s['type']=="Aya" else "Hadeeth",
        "is_valid": False,
        "aya_reference": {} if s['type']=="Hadeeth" else {},
        "hadeeth_reference": {} if s['type']=="Aya" else {},
        "corrected_text": "خطأ",
        "completely_invalid": True
    }
    # ensure both reference objects exist and empty for other type
    if s['type']=="Aya":
        entry["aya_reference"] = {}
        entry["hadeeth_reference"] = {}
    else:
        entry["aya_reference"] = {}
        entry["hadeeth_reference"] = {}
    citations.append(entry)

result = {"citations": citations}
result
